def _load_json(path: pathlib.Path) -> Any:
    return json.loads(path.read_text(encoding="utf-8"))


def _sync_simple_view_fields(state: dict[str, Any]) -> list[str]:
    derived_fields = {
        "last_phase": state.get("previous_phase_id"),
        "phase_now": state.get("phase_id"),
        "next_phase_simple": state.get("next_phase"),
    }
    corrections: list[str] = []
    updated = False
    sentinel = object()

    for field, expected_value in derived_fields.items():
        current_value = state.get(field, sentinel)
        if current_value is sentinel or current_value != expected_value:
            state[field] = expected_value
            corrections.append(field)
            updated = True

    if updated:
        STATE_PATH.write_text(
            json.dumps(state, ensure_ascii=False, indent=4) + "\n",
            encoding="utf-8",
        )

    return corrections


def _load_jsonl(path: pathlib.Path) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for line in path.read_text(encoding="utf-8").splitlines():
        if line.strip():
            rows.append(json.loads(line))
    return rows


def _require(condition: bool, message: str) -> None:
    if not condition:
        raise SystemExit(message)


def _ordered_positions(items: list[str], required: list[str], label: str) -> list[int]:
    missing = [item for item in required if item not in items]
    _require(not missing, f"{label} missing required entries: {missing}")
    positions = [items.index(item) for item in required]
    _require(positions == sorted(positions), f"{label} has out-of-order entries for required list")
    return positions


def _mirror_contains(path: pathlib.Path, *phrases: str) -> None:
    text = path.read_text(encoding="utf-8")
    for phrase in phrases:
        _require(phrase in text, f"{path.name} missing required phrase: {phrase}")


