        def _collect_strings(value: Any) -> list[str]:
            if isinstance(value, str):
                return [value]
            if isinstance(value, list):
                strings: list[str] = []
                for item in value:
                    strings.extend(_collect_strings(item))
                return strings
            if isinstance(value, dict):
                strings = []
                for item in value.values():
                    strings.extend(_collect_strings(item))
                return strings
            return []

